class SecureAuthorizationCodeServices extends InMemoryAuthorizationCodeServices {
    private final Map<String, AuthorizationCode> codes = new ConcurrentHashMap<>();
    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);

    public SecureAuthorizationCodeServices() {
        scheduler.scheduleAtFixedRate(this::cleanupExpiredCodes, 60, 60, TimeUnit.SECONDS);
    }

    @Override
    public void addAuthorizationCode(String code, AuthorizationCode authorizationCode) {
        codes.put(code, new AuthorizationCode(authorizationCode.getClientId(), authorizationCode.getRedirectUri(), System.currentTimeMillis()));
    }

    @Override
    public AuthorizationCode getAuthorizationCode(String code) {
        AuthorizationCode authCode = codes.get(code);
        if (authCode == null) {
            return null;
        }
        if (System.currentTimeMillis() - authCode.getTimestamp() > 600000) {
            codes.remove(code);
            return null;
        }
        return authCode;
    }

    @Override
    public void removeAuthorizationCode(String code) {
        codes.remove(code);
    }

    private void cleanupExpiredCodes() {
        long currentTime = System.currentTimeMillis();
        codes.entrySet().removeIf(entry -> currentTime - entry.getValue().getTimestamp() > 600000);
    }

    public boolean validateRedirectUri(String clientId, String redirectUri) {
        try {
            URI uri = new URI(redirectUri);
            String host = uri.getHost();
            String scheme = uri.getScheme();
            if (!"https".equals(scheme)) {
                return false;
            }
            if (host == null) {
                return false;
            }
            return isAllowedRedirectUri(clientId, redirectUri);
        } catch (URISyntaxException e) {
            return false;
        }
    }

    private boolean isAllowedRedirectUri(String clientId, String redirectUri) {
        List<String> allowedUris = Arrays.asList(
                "https://app.example.com/*",
                "https://*.example.com/*"
        );
        for (String allowedUri : allowedUris) {
            if (allowedUri.endsWith("/*")) {
                String baseUri = allowedUri.substring(0, allowedUri.length() - 1);
                if (redirectUri.startsWith(baseUri)) {
                    return true;
                }
            } else if (redirectUri.equals(allowedUri)) {
                return true;
            }
        }
        return false;
    }
}

class AuthorizationCode {
    private final String clientId;
    private final String redirectUri;
    private final long timestamp;

    public AuthorizationCode(String clientId, String redirectUri, long timestamp) {
        this.clientId = clientId;
        this.redirectUri = redirectUri;
        this.timestamp = timestamp;
    }

    public String getClientId() {
        return clientId;
    }

    public String getRedirectUri() {
        return redirectUri;
    }

    public long getTimestamp() {
        return timestamp;
    }
}

